          </div>
        </div>
      </div>

      <div className="mt-12 pt-8 border-t border-slate-800 text-center text-slate-500 text-xs">
        <p>&copy; {new Date().getFullYear()} Feranclima S.L. Todos los derechos reservados. | Aviso Legal | Privacidad</p>
      </div>
    </div>
  </footer>
);

export default function App() {
  const [avisos, setAvisos] = useState<Aviso[]>(() => {
    const saved = localStorage.getItem('feranclima_avisos');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('feranclima_avisos', JSON.stringify(avisos));
  }, [avisos]);

  const addAviso = (aviso: Aviso) => {
    setAvisos(prev => [aviso, ...prev]);
  };

  const updateAviso = (id: string, updates: Partial<Aviso>) => {
    setAvisos(prev => prev.map(a => a.id === id ? { ...a, ...updates } : a));
  };

  return (
    <HashRouter>
      <div className="min-h-screen flex flex-col">
        <Header />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home onNewAviso={addAviso} />} />
            <Route path="/admin" element={<Admin avisos={avisos} onUpdateAviso={updateAviso} />} />
          </Routes>
        </main>
        <Footer />
      </div>
    </HashRouter>
  );
}

