import React, { useState } from 'react';
import { 
  Printer, 
  Trash2, 
  CheckCircle, 
  Clock, 
  Filter, 
  User,
  MapPin,
  Smartphone,
  ChevronRight
} from 'lucide-react';
import { Aviso } from '../types';
import PrintableSheet from '../components/PrintableSheet';

interface AdminProps {
  avisos: Aviso[];
  onUpdateAviso: (id: string, updates: Partial<Aviso>) => void;
  onDeleteAviso: (id: string) => void;
}

const Admin: React.FC<AdminProps> = ({ avisos, onUpdateAviso, onDeleteAviso }) => {
  const [filterBrand, setFilterBrand] = useState<string>('all');
  const [filterStatus, setFilterStatus] = useState<string>('all');
  const [selectedAviso, setSelectedAviso] = useState<Aviso | null>(null);

  const filteredAvisos = avisos.filter(aviso => {
    const brandMatch = filterBrand === 'all' || aviso.marca === filterBrand;
    const statusMatch = filterStatus === 'all' || aviso.estado === filterStatus;
    return brandMatch && statusMatch;
  });

  const handlePrint = (aviso: Aviso) => {
    setSelectedAviso(aviso);
    setTimeout(() => {
      window.print();
    }, 100);
  };

  return (
    <div className="min-h-screen bg-slate-50 py-12 px-4 sm:px-6 lg:px-8">
      <div className="no-print max-w-7xl mx-auto">
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-12">
          <div>
            <h1 className="text-3xl font-bold text-slate-900 mb-2 tracking-tight">Gestión de Avisos</h1>
            <p className="text-slate-500">Panel de coordinación para técnicos en Madrid y Provincia.</p>
          </div>

          <div className="flex flex-wrap gap-4 bg-white p-2 rounded-2xl shadow-sm border border-slate-200">
            <div className="flex items-center gap-2 px-3 py-1 bg-slate-50 rounded-xl">
              <Filter size={16} className="text-slate-400" />
              <select 
                className="bg-transparent text-sm font-semibold outline-none py-2"
                value={filterBrand}
                onChange={e => setFilterBrand(e.target.value)}
              >
                <option value="all">Todas las Marcas</option>
                <option value="Panasonic">Panasonic</option>
                <option value="Fujitsu">Fujitsu</option>
                <option value="Daitsu">Daitsu</option>
                <option value="Hiyasu">Hiyasu</option>
                <option value="General">General</option>
                <option value="Gree">Gree</option>
              </select>
            </div>

            <div className="flex items-center gap-2 px-3 py-1 bg-slate-50 rounded-xl">
              <Clock size={16} className="text-slate-400" />
              <select 
                className="bg-transparent text-sm font-semibold outline-none py-2"
                value={filterStatus}
                onChange={e => setFilterStatus(e.target.value)}
              >
                <option value="all">Todos los Estados</option>
                <option value="Pendiente">Pendientes</option>
                <option value="Asignado">Asignados</option>
                <option value="Finalizado">Finalizados</option>
              </select>
            </div>
          </div>
        </div>

        <div className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-200">
                  <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Fecha / ID</th>
                  <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Cliente / Zona</th>
                  <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Marca / Tipo</th>
                  <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Avería</th>
                  <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider text-right">Acciones</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredAvisos.length === 0 ? (
                  <tr>
                    <td colSpan={5} className="px-6 py-20 text-center text-slate-400">
                      No se han encontrado avisos con estos criterios.
                    </td>
                  </tr>
                ) : (
                  filteredAvisos.map(aviso => (
                    <tr key={aviso.id} className="hover:bg-slate-50 transition-colors group">
                      <td className="px-6 py-4">
                        <div className="text-sm font-bold text-slate-900">{new Date(aviso.fechaEntrada).toLocaleDateString('es-ES')}</div>
                        <div className="text-[10px] text-slate-400 font-mono uppercase">{aviso.id}</div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2 mb-1">
                          <User size={14} className="text-slate-400" />
                          <div className="text-sm font-semibold text-slate-800">{aviso.nombre}</div>
                        </div>
                        <div className="flex items-center gap-2 mb-1">
                          <MapPin size={14} className="text-slate-400" />
                          <div className="text-xs text-slate-500">{aviso.poblacion} ({aviso.codigoPostal})</div>
                        </div>
                        <div className="flex items-center gap-2">
                          <Smartphone size={14} className="text-slate-400" />
                          <div className="text-xs text-slate-500">{aviso.telefono1}</div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="inline-block px-2 py-0.5 rounded-md bg-cyan-50 text-cyan-700 text-xs font-bold mb-1">{aviso.marca}</div>
                        <div className="text-xs text-slate-500">{aviso.tipoAparato}</div>
                      </td>
                      <td className="px-6 py-4">
                        <p className="text-xs text-slate-600 line-clamp-2 max-w-xs">{aviso.descripcion}</p>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex items-center justify-end gap-2">
                          <button 
                            onClick={() => onUpdateAviso(aviso.id, { estado: aviso.estado === 'Finalizado' ? 'Pendiente' : 'Finalizado' })}
                            className={`p-2 rounded-lg transition-all ${aviso.estado === 'Finalizado' ? 'bg-green-100 text-green-600' : 'bg-slate-100 text-slate-400 hover:text-cyan-600'}`}
                            title="Cambiar estado"
                          >
                            <CheckCircle size={18} />
                          </button>
                          <button 
                            onClick={() => handlePrint(aviso)}
                            className="p-2 bg-slate-100 text-slate-600 rounded-lg hover:bg-slate-900 hover:text-white transition-all"
                            title="Imprimir Hoja de Trabajo"
                          >
                            <Printer size={18} />
                          </button>
                          <button 
                            onClick={() => onDeleteAviso(aviso.id)}
                            className="p-2 bg-slate-100 text-slate-400 rounded-lg hover:bg-red-50 hover:text-red-600 transition-all"
                            title="Eliminar aviso"
                          >
                            <Trash2 size={18} />
                          </button>
                        </div>
                      </td>
