export default function App() {
  const [avisos, setAvisos] = useState<Aviso[]>(() => {
    const saved = localStorage.getItem('feranclima_avisos');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('feranclima_avisos', JSON.stringify(avisos));
  }, [avisos]);

  const addAviso = (aviso: Aviso) => {
    setAvisos(prev => [aviso, ...prev]);
  };

  const updateAviso = (id: string, updates: Partial<Aviso>) => {
    setAvisos(prev => prev.map(a => a.id === id ? { ...a, ...updates } : a));
  };

  const deleteAviso = (id: string) => {
    if (confirm('¿Está seguro de que desea eliminar este aviso?')) {
      setAvisos(prev => prev.filter(a => a.id !== id));
    }
  };

  return (
    <HashRouter>
      <div className="min-h-screen flex flex-col">
        <Header />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home onNewAviso={addAviso} />} />
            <Route path="/admin" element={<Admin avisos={avisos} onUpdateAviso={updateAviso} onDeleteAviso={deleteAviso} />} />
          </Routes>
        </main>
        <Footer />
      </div>
    </HashRouter>
  );
}

