                <button 
                  type="submit"
                  className="w-full bg-red-600 hover:bg-red-700 text-white font-black py-5 rounded-2xl shadow-xl shadow-red-200 transition-all flex items-center justify-center gap-4 text-xl transform active:scale-95"
