const App = () => {
  const [avisos, setAvisos] = useState<Aviso[]>(() => {
    const saved = localStorage.getItem('feranclima_avisos');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('feranclima_avisos', JSON.stringify(avisos));
  }, [avisos]);

  const handleNewAviso = (aviso: Aviso) => {
    setAvisos(prev => [aviso, ...prev]);
  };

  const handleUpdateAviso = (id: string, updates: Partial<Aviso>) => {
    setAvisos(prev => prev.map(a => a.id === id ? { ...a, ...updates } : a));
  };

  const handleDeleteAviso = (id: string) => {
    if (window.confirm('¿Está seguro de eliminar este aviso?')) {
      setAvisos(prev => prev.filter(a => a.id !== id));
    }
  };

  return (
    <HashRouter>
      <div className="min-h-screen flex flex-col font-sans selection:bg-[#004598] selection:text-white">
        <Header />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home onNewAviso={handleNewAviso} />} />
            <Route path="/admin" element={<Admin avisos={avisos} onUpdateAviso={handleUpdateAviso} onDeleteAviso={handleDeleteAviso} />} />
            <Route path="/marca/:brandId" element={<BrandLanding onNewAviso={handleNewAviso} />} />
          </Routes>
        </main>
        <Footer />
      </div>
    </HashRouter>
  );
};

export default App;

